1443	// commitTrackerLocked is the body of CommitTracker without the lock
1444	// acquisition. Callers must hold withTrackerLock(projectRoot) before calling.
1445	// Used by Run() to fold tracker commit, checkpoint synthesis, and worktree
1446	// creation into a single critical section so concurrent workers do not race
1447	// on the parent's HEAD ref (regression: niflheim concurrent `ddx work` hit
1448	// "cannot lock ref 'HEAD'" between unlocked CommitTracker and SynthesizeCommit).
1449	func commitTrackerLocked(projectRoot string) error {
1450		trackerFile := filepath.Join(projectRoot, ".ddx", "beads.jsonl")
1451		info, err := os.Stat(trackerFile)
1452		if err != nil {
1453			if os.IsNotExist(err) {
1454				return nil
1455			}
1456			return fmt.Errorf("checking tracker file: %w", err)
1457		}
1458		if info.IsDir() {
1459			return nil
1460		}
1461	
1462		out, err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--is-inside-work-tree").Output()
1463		if err != nil || strings.TrimSpace(string(out)) != "true" {
1464			return nil
1465		}
1466	
1467		msg := fmt.Sprintf("chore: update tracker (execute-bead %s)", time.Now().UTC().Format("20060102T150405"))
1468	
1469		// Re-check inside the lock: a sibling worker may have already
1470		// committed the tracker changes between our pre-lock check and now.
1471		diff, err := internalgit.Command(context.Background(), projectRoot, "diff", "--", ".ddx/beads.jsonl").Output()
1472		if err != nil {
1473			return fmt.Errorf("checking tracker diff: %w", err)
1474		}
1475		if strings.TrimSpace(string(diff)) == "" {
1476			untracked, err := internalgit.Command(context.Background(), projectRoot, "ls-files", "--others", "--exclude-standard", ".ddx/beads.jsonl").Output()
1477			if err != nil {
1478				return fmt.Errorf("checking tracker untracked: %w", err)
1479			}
1480			if strings.TrimSpace(string(untracked)) == "" {
1481				return nil
1482			}
1483		}
1484	
1485		commitOut, err := internalgit.Command(context.Background(), projectRoot, "add", ".ddx/beads.jsonl").CombinedOutput()
1486		if err != nil {
1487			return fmt.Errorf("staging tracker: %s: %w", strings.TrimSpace(string(commitOut)), err)
1488		}
1489		// `git commit` would fail with "nothing to commit" if the file's
1490		// content is byte-identical to HEAD even though `git diff` saw a
1491		// diff (e.g. mode/whitespace race). Bail cleanly in that case.
1492		if cached, err := internalgit.Command(context.Background(), projectRoot, "diff", "--cached", "--", ".ddx/beads.jsonl").Output(); err == nil && strings.TrimSpace(string(cached)) == "" {
1493			return nil
1494		}
1495		commitOut, err = internalgit.Command(context.Background(), projectRoot, "commit", "--no-verify", "--only", "-m", msg, "--", ".ddx/beads.jsonl").CombinedOutput()
1496		if err != nil {
1497			return fmt.Errorf("committing tracker: %s: %w", strings.TrimSpace(string(commitOut)), err)
1498		}
1499		return nil
1500	}
